package com.monthlyexpo.repository; import com.monthlyexpo.entity.TractorExpense; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.math.BigDecimal; import java.time.LocalDate; public interface TractorExpenseRepository extends JpaRepository<TractorExpense,Long>{ @Query("select coalesce(sum(e.amount),0) from TractorExpense e where e.expenseDate between :from and :to") BigDecimal totalBetween(@Param("from") LocalDate from,@Param("to") LocalDate to); }
